/** Étoiles de notation */
const Stars = ({ note }) => (
  <div style={{ display:"flex", gap:1, alignItems:"center" }}>
    {[1,2,3,4,5].map(i => (
      <Star key={i} size={11}
        fill={i <= Math.round(note) ? "#F59E0B" : "none"}
        color={i <= Math.round(note) ? "#F59E0B" : "#D1D5DB"}
        strokeWidth={1.5} />
    ))}
    <span style={{ fontSize:11, color:"#6B7280", marginLeft:3 }}>{note}</span>
  </div>
);

/** Carte Produit Vivrier */
const ProductCard = ({ p, onAdd, added }) => (
  <div style={{
    background:"#fff", borderRadius:20, overflow:"hidden",
    boxShadow:"0 2px 16px rgba(0,0,0,0.07)",
    border:"1px solid #F1F5F9",
    transition:"transform 0.15s, box-shadow 0.15s",
    cursor:"pointer",
  }}>
    <div style={{ position:"relative" }}>
      <img src={p.img} alt={p.name}
        style={{ width:"100%", height:110, objectFit:"cover", display:"block" }}
        onError={e => { e.target.style.background="#F8F4EF"; e.target.style.display="none"; }} />
      {p.badge && (
        <span style={{
          position:"absolute", top:8, left:8,
          background:"rgba(255,255,255,0.92)", backdropFilter:"blur(4px)",
          fontSize:10, fontWeight:700, color:"#1C0F06",
          borderRadius:20, padding:"3px 8px",
          boxShadow:"0 1px 4px rgba(0,0,0,0.10)"
        }}>{p.badge}</span>
      )}
    </div>
    <div style={{ padding:"12px 12px 14px" }}>
      <div style={{ fontSize:13, fontWeight:700, color:"#111827", marginBottom:2 }}>{p.name}</div>
      <div style={{ fontSize:12, color:"#9CA3AF", marginBottom:10 }}>
        {p.price.toLocaleString()} F / {p.unit}
      </div>
      <button onClick={() => onAdd(p.id)}
        style={{
          width:"100%",
          background: added ? "#6DC030" : "#3D3DB8",
          border:"none", borderRadius:12, padding:"8px 0",
          color:"#fff", fontSize:12, fontWeight:700,
          cursor:"pointer", transition:"all 0.3s",
          boxShadow: added ? "0 3px 12px #6DC03044" : "0 3px 12px #3D3DB833"
        }}>
        {added ? "✓ Ajouté" : "+ Panier"}
      </button>
    </div>
  </div>
);

